 25→fn position_near_top(window: &tauri::WebviewWindow) {
 26→    let monitor = window
 27→        .current_monitor()
 28→        .ok()
 29→        .flatten()
 30→        .or_else(|| window.primary_monitor().ok().flatten());
 31→
 32→    if let Some(monitor) = monitor {
 33→        let monitor_size = monitor.size();
 34→        let monitor_pos = monitor.position();
 35→
 36→        if let Ok(window_size) = window.outer_size() {
 37→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 38→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 39→
 40→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 41→                eprintln!("failed to position window: {e}");
 42→            }
 43→        }
 44→    } else if let Err(e) = window.center() {
 45→        eprintln!("failed to center window: {e}");
 46→    }
 47→}
