 72→fn toggle_window(window: &tauri::WebviewWindow) {
 73→    let visible = window.is_visible().unwrap_or(false);
 74→    let focused = window.is_focused().unwrap_or(false);
 75→
 76→    if visible && focused {
 77→        if let Err(e) = window.hide() {
 78→            eprintln!("failed to hide window: {e}");
 79→        }
 80→    } else if visible {
 81→        show_and_focus(window);
 82→    } else {
 83→        show_and_focus(window);
 84→    }
 85→}
