112→fn start_clipboard_monitor(app_handle: tauri::AppHandle) {
113→    use tauri_plugin_clipboard_manager::ClipboardExt;
114→
115→    std::thread::spawn(move || {
116→        let mut last_text = String::new();
117→
118→        loop {
119→            std::thread::sleep(Duration::from_millis(500));
120→
121→            let text = match app_handle.clipboard().read_text() {
122→                Ok(t) => t,
123→                Err(_) => continue,
124→            };
125→
126→            if text.is_empty() || text == last_text {
127→                continue;
128→            }
129→            last_text = text.clone();
130→
131→            let content_type = detect_content_type(&text);
132→
133→            let elapsed = std::time::SystemTime::now()
134→                .duration_since(std::time::UNIX_EPOCH)
135→                .unwrap_or_default();
136→            let timestamp_ms = elapsed.as_secs() * 1000 + elapsed.subsec_millis() as u64;
137→
138→            let payload = serde_json::json!({
139→                "content": text,
140→                "contentType": content_type,
141→                "timestamp": timestamp_ms,
142→            });
143→
144→            if let Err(e) = app_handle.emit("clipboard-changed", payload) {
145→                eprintln!("failed to emit clipboard-changed: {e}");
146→            }
147→        }
148→    });
149→}
