163→fn detect_file_type(path: &std::path::Path) -> &'static str {
164→    if path.is_dir() {
165→        return "folder";
166→    }
167→
168→    match path
169→        .extension()
170→        .and_then(|e| e.to_str())
171→        .map(|e| e.to_lowercase())
172→        .as_deref()
173→    {
174→        Some(
175→            "ts" | "tsx" | "js" | "jsx" | "rs" | "py" | "rb" | "go" | "java" | "c" | "cpp" | "h"
176→            | "hpp" | "cs" | "swift" | "kt" | "scala" | "sh" | "bash" | "zsh" | "json" | "yaml"
177→            | "yml" | "toml" | "xml" | "html" | "css" | "scss" | "less" | "sql" | "graphql"
178→            | "proto" | "lua" | "r" | "php" | "pl" | "ex" | "exs" | "erl" | "hs" | "ml"
179→            | "vim" | "el" | "clj" | "dart",
180→        ) => "code",
181→        Some("png" | "jpg" | "jpeg" | "gif" | "bmp" | "svg" | "webp" | "ico" | "tiff" | "avif") => {
182→            "image"
183→        }
184→        Some("pdf") => "pdf",
185→        Some("zip" | "tar" | "gz" | "bz2" | "xz" | "7z" | "rar" | "dmg" | "iso") => "archive",
186→        Some("xlsx" | "xls" | "csv" | "numbers" | "ods") => "spreadsheet",
187→        Some("pptx" | "ppt" | "key" | "odp") => "presentation",
188→        Some(
189→            "md" | "txt" | "rtf" | "doc" | "docx" | "pages" | "odt" | "tex" | "log" | "conf"
190→            | "cfg" | "ini" | "env" | "fig",
191→        ) => "document",
192→        _ => "document",
193→    }
194→}
