196→fn is_ignored_dir(name: &str) -> bool {
197→    matches!(
198→        name,
199→        ".git"
200→            | "node_modules"
201→            | ".DS_Store"
202→            | "__pycache__"
203→            | ".next"
204→            | ".cache"
205→            | ".vscode"
206→            | ".idea"
207→            | "target"
208→            | "dist"
209→            | "build"
210→            | ".Trash"
211→    )
212→}
