215→fn search_files(query: String, paths: Vec<String>, max_results: usize) -> Vec<FileEntryResult> {
216→    let max = if max_results == 0 { 200 } else { max_results };
217→    let query_lower = query.to_lowercase();
218→    let mut results: Vec<FileEntryResult> = Vec::new();
219→
220→    let search_paths: Vec<String> = if paths.is_empty() {
221→        if let Some(home) = dirs_next::home_dir() {
222→            let home_str = home.to_string_lossy().to_string();
223→            vec![
224→                format!("{home_str}/Documents"),
225→                format!("{home_str}/Downloads"),
226→                format!("{home_str}/Desktop"),
227→                format!("{home_str}/Projects"),
228→                home_str,
229→            ]
230→        } else {
231→            return results;
232→        }
233→    } else {
234→        paths
235→    };
236→
237→    for search_path in &search_paths {
238→        if results.len() >= max {
239→            break;
240→        }
241→
242→        let walker = WalkDir::new(search_path)
243→            .max_depth(5)
244→            .follow_links(false)
245→            .into_iter()
246→            .filter_entry(|entry| {
247→                let name = entry.file_name().to_string_lossy();
248→                if name.starts_with('.') && entry.depth() > 0 {
249→                    return false;
250→                }
251→                if entry.file_type().is_dir() && is_ignored_dir(&name) {
252→                    return false;
253→                }
254→                true
255→            });
256→
257→        for entry in walker.flatten() {
258→            if results.len() >= max {
259→                break;
260→            }
261→
262→            let name = entry.file_name().to_string_lossy().to_string();
263→
264→            if !query_lower.is_empty() && !name.to_lowercase().contains(&query_lower) {
265→                continue;
266→            }
267→
268→            if entry.depth() == 0 {
269→                continue;
270→            }
271→
272→            let path = entry.path();
273→            let metadata = match entry.metadata() {
274→                Ok(m) => m,
275→                Err(_) => continue,
276→            };
277→
278→            let size = metadata.len();
279→            let modified_at = metadata
280→                .modified()
281→                .ok()
282→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
283→                .map(|d| d.as_millis() as u64)
284→                .unwrap_or(0);
285→
286→            let file_type = detect_file_type(path);
287→            let path_str = path.to_string_lossy().to_string();
288→
289→            let id = format!("fs-{}", results.len());
290→
291→            results.push(FileEntryResult {
292→                id,
293→                name,
294→                path: path_str,
295→                file_type: file_type.to_string(),
296→                size,
297→                modified_at,
298→            });
299→        }
300→    }
301→
302→    results
303→}
