310→#[tauri::command]
311→fn reveal_in_finder(path: String) -> Result<(), String> {
312→    #[cfg(target_os = "macos")]
313→    {
314→        std::process::Command::new("open")
315→            .arg("-R")
316→            .arg(&path)
317→            .spawn()
318→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
319→        return Ok(());
320→    }
321→
322→    #[cfg(target_os = "windows")]
323→    {
324→        std::process::Command::new("explorer")
325→            .arg(format!("/select,{}", &path))
326→            .spawn()
327→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
328→        return Ok(());
329→    }
330→
331→    #[cfg(target_os = "linux")]
332→    {
333→        std::process::Command::new("xdg-open")
334→            .arg(
335→                std::path::Path::new(&path)
336→                    .parent()
337→                    .map(|p| p.to_string_lossy().to_string())
338→                    .unwrap_or(path),
339→            )
340→            .spawn()
341→            .map_err(|e| format!("failed to reveal: {e}"))?;
342→        return Ok(());
343→    }
344→
345→    #[allow(unreachable_code)]
346→    Err("unsupported platform".to_string())
347→}
