349→#[tauri::command]
350→fn move_to_trash(path: String) -> Result<(), String> {
351→    #[cfg(target_os = "macos")]
352→    {
353→        let script = format!(
354→            "tell application \"Finder\" to delete POSIX file \"{}\"",
355→            path.replace('\"', "\\\"")
356→        );
357→        std::process::Command::new("osascript")
358→            .arg("-e")
359→            .arg(&script)
360→            .output()
361→            .map_err(|e| format!("failed to trash {path}: {e}"))?;
362→        return Ok(());
363→    }
364→
365→    #[cfg(target_os = "linux")]
366→    {
367→        std::process::Command::new("gio")
368→            .args(["trash", &path])
369→            .output()
370→            .map_err(|e| format!("failed to trash {path}: {e}"))?;
371→        return Ok(());
372→    }
373→
374→    #[cfg(target_os = "windows")]
375→    {
376→        std::fs::remove_file(&path).map_err(|e| format!("failed to delete {path}: {e}"))?;
377→        return Ok(());
378→    }
379→
380→    #[allow(unreachable_code)]
381→    Err("unsupported platform".to_string())
382→}
