384→#[tauri::command]
385→fn set_window_position_pref(
386→    state: tauri::State<'_, Mutex<WindowConfig>>,
387→    position: String,
388→) -> Result<(), String> {
389→    match position.as_str() {
390→        "center" | "top-third" => {
391→            if let Ok(mut config) = state.lock() {
392→                config.position_pref = position;
393→                Ok(())
