403→pub fn run() {
404→    tauri::Builder::default()
405→        .plugin(tauri_plugin_clipboard_manager::init())
406→        .plugin(tauri_plugin_shell::init())
407→        .manage(Mutex::new(WindowConfig::default()))
408→        .invoke_handler(tauri::generate_handler![
409→            set_window_position_pref,
410→            search_files,
411→            open_file,
412→            reveal_in_finder,
413→            move_to_trash
414→        ])
415→        .setup(|app| {
416→            #[cfg(desktop)]
417→            {
418→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
419→                let window = app
420→                    .get_webview_window("main")
421→                    .expect("main window not found");
422→
423→                let window_for_blur = window.clone();
424→                window.on_window_event(move |event| {
425→                    if let tauri::WindowEvent::Focused(false) = event {
426→                        if let Err(e) = window_for_blur.hide() {
427→                            eprintln!("failed to hide on blur: {e}");
428→                        }
429→                    }
430→                });
431→
432→                #[cfg(target_os = "macos")]
433→                {
434→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
435→                    if let Err(e) =
436→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
437→                    {
438→                        eprintln!("failed to apply vibrancy: {e}");
439→                    }
440→                }
441→
442→                position_near_top(&window);
443→
444→                start_clipboard_monitor(app.handle().clone());
445→
446→                let window_for_shortcut = window.clone();
447→                app.handle().plugin(
448→                    tauri_plugin_global_shortcut::Builder::new()
449→                        .with_handler(move |_app, scut, event| {
450→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
451→                                toggle_window(&window_for_shortcut);
452→                            }
453→                        })
454→                        .build(),
455→                )?;
456→
457→                app.global_shortcut().register(shortcut)?;
458→
459→                let show_item =
460→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
461→                let clipboard_item =
462→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
463→                let snippets_item =
464→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
465→                let settings_item =
466→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
467→                let check_updates_item = MenuItem::with_id(
468→                    app,
469→                    "check-updates",
470→                    "Check for Updates",
471→                    true,
472→                    None::<&str>,
473→                )?;
474→                let about_item =
475→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
476→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
477→
478→                let menu = Menu::with_items(
479→                    app,
480→                    &[
481→                        &show_item,
482→                        &PredefinedMenuItem::separator(app)?,
483→                        &clipboard_item,
484→                        &snippets_item,
485→                        &settings_item,
486→                        &PredefinedMenuItem::separator(app)?,
487→                        &check_updates_item,
488→                        &about_item,
489→                        &quit_item,
490→                    ],
491→                )?;
492→
493→                let window_for_menu = window.clone();
494→                let window_for_tray = window.clone();
495→
496→                TrayIconBuilder::new()
497→                    .icon(tauri::image::Image::from_bytes(include_bytes!(
498→                        "../icons/tray-icon@2x.png"
499→                    ))?)
500→                    .icon_as_template(true)
501→                    .tooltip("Raycast Clone")
502→                    .menu(&menu)
503→                    .show_menu_on_left_click(false)
504→                    .on_menu_event(move |app, event| match event.id().as_ref() {
505→                        "show" => {
506→                            show_and_focus(&window_for_menu);
507→                        }
508→                        "clipboard" | "snippets" | "settings" | "about" | "check-updates" => {
509→                            show_and_focus(&window_for_menu);
510→                            if let Err(e) =
511→                                app.emit("tray-navigate", event.id().as_ref().to_string())
512→                            {
513→                                eprintln!("failed to emit tray-navigate: {e}");
514→                            }
515→                        }
516→                        "quit" => {
517→                            app.exit(0);
518→                        }
519→                        _ => {}
520→                    })
521→                    .on_tray_icon_event(move |_tray, event| {
522→                        if let TrayIconEvent::Click {
523→                            button: MouseButton::Left,
524→                            button_state: MouseButtonState::Up,
525→                            ..
526→                        } = event
527→                        {
528→                            toggle_window(&window_for_tray);
529→                        }
530→                    })
531→                    .build(app)?;
532→            }
533→
534→            Ok(())
535→        })
536→        .run(tauri::generate_context!())
537→        .expect("error while running tauri application");
538→}
